import { Link, useLocation, useNavigate } from 'react-router-dom';

import Button from '@mui/material/Button';
import FormHelperText from '@mui/material/FormHelperText';
import Grid from '@mui/material/Grid';
import InputLabel from '@mui/material/InputLabel';
import OutlinedInput from '@mui/material/OutlinedInput';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import { Formik } from 'formik';
import * as Yup from 'yup';

import useToast from 'app/providers/useToast';
import extractApiErrorMessage from 'utils/apiError';
import AuthWrapper from 'sections/auth/AuthWrapper';

import useAuth from '../useAuth';

export default function LoginPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const { showToast } = useToast();
  const { login } = useAuth();

  const fromPath = location.state?.from?.pathname || '/';

  return (
    <AuthWrapper>
      <Grid container spacing={2}>
        <Grid size={12}>
          <Stack direction="row" sx={{ justifyContent: 'space-between', alignItems: 'baseline' }}>
            <Typography variant="h3">Iniciar sesión</Typography>
            <Typography component={Link} to="/register" variant="body1" color="primary" sx={{ textDecoration: 'none' }}>
              Crear cuenta
            </Typography>
          </Stack>
        </Grid>
        <Grid size={12}>
          <Formik
            initialValues={{ email: '', password: '' }}
            validationSchema={Yup.object({
              email: Yup.string().email('Correo inválido').required('Correo requerido'),
              password: Yup.string().required('Contraseña requerida')
            })}
            onSubmit={async (values, { setSubmitting }) => {
              try {
                await login(values);
                showToast('Bienvenido al sistema.', 'success');
                navigate(fromPath, { replace: true });
              } catch (err) {
                showToast(extractApiErrorMessage(err, 'Credenciales inválidas.'), 'error');
              } finally {
                setSubmitting(false);
              }
            }}
          >
            {({ values, errors, touched, handleBlur, handleChange, handleSubmit, isSubmitting }) => (
              <form onSubmit={handleSubmit}>
                <Grid container spacing={2}>
                  <Grid size={12}>
                    <Stack sx={{ gap: 1 }}>
                      <InputLabel htmlFor="email">Correo</InputLabel>
                      <OutlinedInput id="email" name="email" value={values.email} onChange={handleChange} onBlur={handleBlur} />
                      {touched.email && errors.email ? <FormHelperText error>{errors.email}</FormHelperText> : null}
                    </Stack>
                  </Grid>
                  <Grid size={12}>
                    <Stack sx={{ gap: 1 }}>
                      <InputLabel htmlFor="password">Contraseña</InputLabel>
                      <OutlinedInput
                        id="password"
                        name="password"
                        type="password"
                        value={values.password}
                        onChange={handleChange}
                        onBlur={handleBlur}
                      />
                      {touched.password && errors.password ? <FormHelperText error>{errors.password}</FormHelperText> : null}
                    </Stack>
                  </Grid>
                  <Grid size={12}>
                    <Stack direction="row" sx={{ justifyContent: 'space-between' }}>
                      <Typography component={Link} to="/password-reset" variant="body2" color="primary" sx={{ textDecoration: 'none' }}>
                        Recuperar contraseña
                      </Typography>
                    </Stack>
                  </Grid>
                  <Grid size={12}>
                    <Button type="submit" variant="contained" fullWidth disabled={isSubmitting}>
                      Entrar
                    </Button>
                  </Grid>
                </Grid>
              </form>
            )}
          </Formik>
        </Grid>
      </Grid>
    </AuthWrapper>
  );
}
